-- STEP 1: query [kommuner]
SELECT omrade FROM kommuner.kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Stavanger%';

-- STEP BOUNDARY --

-- STEP 2: query [arealressurskart_ar50]
SELECT gid, artype, geom FROM arealressurskart_ar50.arealressurskart_ar50_gis.ar50 WHERE artype = 1 AND ST_Intersects(geom, (SELECT omrade FROM kommuner.kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Stavanger%'));

args.sql:
WITH stavanger AS (
    SELECT omrade FROM kommuner.kommuner_627ee106072240e99d2b21ec4717bf01.kommune WHERE kommunenavn ILIKE '%Stavanger%'
),
agricultural_land AS (
    SELECT gid, geom FROM arealressurskart_ar50.arealressurskart_ar50_gis.ar50 WHERE arjordbr = 1
)
SELECT teig.gid, teig.teigid, teig.geom FROM matrikkeleneiendomskartteig.matrikkeleneiendomskartteig_gis.teig
JOIN stavanger ON ST_Intersects(stavanger.omrade, teig.geom)
JOIN agricultural_land ON ST_Intersects(agricultural_land.geom, teig.geom);

